oxy_webhelp_navlinks = {"mysql-d30753e31027":{"topics":[{"title":"Introduction to MySQL protection","href":"mysql\/mysql_protection_key_features.html","menu":{"hasChildren":false},"tocID":"tocId-d30753e31040","next":"tocId-d30753e31040"},{"title":"Plan your MySQL protection","shortdesc":"<p class=\"shortdesc\">Before setting up a MySQL instance in <span class=\"ph\">RSC<\/span>, it is necessary to plan         user and access management for designated <span class=\"ph\">RSC<\/span> users. This planning also         involves reviewing the permissions that <span class=\"ph\">RSC<\/span> requires in your MySQL         environment to protect your MySQL instance.<\/p>","href":"mysql\/mysql_planning_protection.html","attributes":{"data-id":"mysql_planning_protection"},"menu":{"hasChildren":false},"tocID":"mysql_planning_protection-d30753e31093","next":"mysql_planning_protection-d30753e31093"},{"title":"Set up your MySQL system","shortdesc":"<p class=\"shortdesc\">You can protect MySQL database using <span class=\"ph\">RSC<\/span> by configuring MySQL hosts         and instances with it. This setup automates backups and enables rapid recovery from threats         such as ransomware, providing unified data security and resilience for your MySQL         databases.<\/p>","href":"mysql\/mysql_setup.html","attributes":{"data-id":"mysql_setup"},"menu":{"hasChildren":false},"tocID":"mysql_setup-d30753e31171","next":"mysql_setup-d30753e31171"},{"title":"Protect MySQL databases","shortdesc":"<p class=\"shortdesc\">Protect MySQL instances using automated, policy-driven backups, ensuring data         resilience and compliance with organizational standards.<\/p>","href":"mysql\/mysql_protection_setup.html","attributes":{"data-id":"mysql_protection_setup"},"menu":{"hasChildren":false},"tocID":"mysql_protection_setup-d30753e31288","next":"mysql_protection_setup-d30753e31288"},{"title":"Recover MySQL data","shortdesc":"<p class=\"shortdesc\">After <span class=\"ph\">RSC<\/span> takes snapshots of your MySQL workloads, you can recover         the required workloads using different recovery options.<\/p>","href":"mysql\/mysql_recovery.html","attributes":{"data-id":"mysql_recovery"},"menu":{"hasChildren":false},"tocID":"mysql_recovery-d30753e31562","next":"mysql_recovery-d30753e31562"}]}};